/*!
 * Cargador local de PizZip para guardarecursos_conap
 * Este archivo se coloca en docs/assets/pizzip.min.js
 * Carga PizZip desde CDNs públicos con fallback.
 */
(function () {
  "use strict";

  if (window.PizZip) {
    window.PizZipReady = Promise.resolve(window.PizZip);
    return;
  }

  var urls = [
    "https://cdn.jsdelivr.net/npm/pizzip@3.2.0/dist/pizzip.min.js",
    "https://unpkg.com/pizzip@3.2.0/dist/pizzip.min.js",
    "https://cdn.jsdelivr.net/npm/pizzip@3.1.8/dist/pizzip.min.js",
    "https://unpkg.com/pizzip@3.1.8/dist/pizzip.min.js"
  ];

  window.PizZipReady = new Promise(function (resolve, reject) {
    var index = 0;

    function cargarSiguiente() {
      if (window.PizZip) {
        resolve(window.PizZip);
        return;
      }

      if (index >= urls.length) {
        var err = new Error("No se pudo cargar PizZip desde ninguna fuente.");
        window.PIZZIP_LOCAL_LOAD_FAILED = true;
        console.error(err);
        reject(err);
        return;
      }

      var script = document.createElement("script");
      script.src = urls[index++];
      script.async = false;
      script.crossOrigin = "anonymous";

      script.onload = function () {
        if (window.PizZip) {
          resolve(window.PizZip);
        } else {
          cargarSiguiente();
        }
      };

      script.onerror = function () {
        cargarSiguiente();
      };

      document.head.appendChild(script);
    }

    cargarSiguiente();
  });
})();
